          "id": "T17",
          "name": "a. Abnormal Molar Masses and Van't Hoff Factor",
          "theory": "",
          "questions": [],
          "workedExamples": [
            {
              "id": "we_chem_1_T17_1",
              "prompt": "Find the van't Hoff factor i for $K_2SO_4$ assuming complete dissociation, and the freezing point depression for 0.01 m aqueous $K_2SO_4$ ($K_f = 1.86$).",
              "steps": [
                "$K_2SO_4 \\to 2K^+ + SO_4^{2-}$: 3 ions, so $i = 3$ (complete dissociation).",
                "$\\Delta T_f = i\\cdot K_f\\cdot m = 3\\times 1.86\\times 0.01$.",
                "Compute: $\\Delta T_f \\approx 0.0558$ K."
              ],
              "finalAnswer": "$i = 3$; $\\Delta T_f \\approx 0.056$ K.",
              "_source": "Authored from NCERT/ISC pattern"
            }
          ]
