          "theory": "",
          "questions": [],
          "workedExamples": [
            {
              "id": "we_chem_6_T9_1",
              "prompt": "Predict whether $\\text{(CH}_3)_3\\text{CBr}$ reacts via SN1 or SN2 with aqueous OH⁻ and explain.",
              "steps": [
                "(CH₃)₃CBr is tertiary; the C bearing Br has three bulky methyl groups.",
                "Steric crowding blocks back-side attack required for SN2.",
                "However, the resulting tertiary carbocation is highly stable, so it favours SN1."
              ],
              "finalAnswer": "SN1 — stable 3° carbocation; SN2 blocked by steric hindrance.",
              "_source": "Authored from NCERT/ISC pattern"
            }
          ]
